import os, base64, urllib.request, json, py_compile, tempfile

token     = os.environ.get("GITHUB_TOKEN", "")
repo      = "dperuffo/estudo-de-rede"
arquivo_sb = "/app/stripe_billing.py"
arquivo_mn = "/app/estudo_de_rede.py"

with open(arquivo_sb, "r", encoding="utf-8") as f: src_sb = f.read()
with open(arquivo_mn, "r", encoding="utf-8") as f: src_mn = f.read()
print(f"stripe_billing.py: {len(src_sb):,} chars")
print(f"estudo_de_rede.py:  {len(src_mn):,} chars")

# Bloco de melhorias em base64
BLOCO_B64 = ""
bloco = base64.b64decode(BLOCO_B64.encode()).decode("utf-8")

# Injeta no stripe_billing.py
if "BLOCO_IMPORTS_MELHORIAS_V1" not in src_sb:
    linhas = src_sb.split(chr(10))
    idx = 0
    for i, l in enumerate(linhas):
        if l.startswith("import ") or l.startswith("from "): idx = i
    src_sb = chr(10).join(linhas[:idx+1]) + chr(10) + bloco + chr(10) + chr(10).join(linhas[idx+1:])
    print("OK 1: bloco de melhorias injetado")
else:
    print("SKIP 1: bloco ja presente")

# Injeta chamada ao webhook
WH_MARKER = '"checkout.session.completed"'
WH_CALL = "            try:" + chr(10) + "                _webhook_pos_pagamento(session)" + chr(10) + "            except Exception:" + chr(10) + "                pass" + chr(10)
if WH_MARKER in src_sb and "_webhook_pos_pagamento" not in src_sb.split(WH_MARKER)[1][:600]:
    idx_wh  = src_sb.find(WH_MARKER)
    idx_end = src_sb.index(chr(10), idx_wh)
    src_sb  = src_sb[:idx_end+1] + WH_CALL + src_sb[idx_end+1:]
    print("OK 2: _webhook_pos_pagamento injetado no handler")
else:
    print("SKIP 2: webhook ja com chamada ou marcador ausente")

# Atualiza estudo_de_rede.py
OLD_CALL = "        from stripe_billing import mostrar_tela_planos" + chr(10) + "        mostrar_tela_planos()"
NEW_CALL = "        from stripe_billing import _mostrar_tela_planos_com_termo" + chr(10) + "        _mostrar_tela_planos_com_termo()"
if OLD_CALL in src_mn:
    src_mn = src_mn.replace(OLD_CALL, NEW_CALL, 1)
    print("OK 3: estudo_de_rede.py atualizado")
elif "_mostrar_tela_planos_com_termo" in src_mn:
    print("SKIP 3: ja usa wrapper")
else:
    print("WARN 3: padrao nao encontrado")

# Valida sintaxe
for nome, conteudo in [("stripe_billing.py", src_sb), ("estudo_de_rede.py", src_mn)]:
    with tempfile.NamedTemporaryFile(suffix=".py", delete=False, mode="w", encoding="utf-8") as tmp:
        tmp.write(conteudo)
        tp = tmp.name
    try:
        py_compile.compile(tp, doraise=True)
        print(f"Sintaxe OK: {nome}")
    except py_compile.PyCompileError as e:
        print(f"ERRO SINTAXE {nome}: {e}")
        exit(1)

# Salva localmente
with open(arquivo_sb, "w", encoding="utf-8") as f: f.write(src_sb)
with open(arquivo_mn, "w", encoding="utf-8") as f: f.write(src_mn)
print("Arquivos salvos localmente")

# Push GitHub
def _push(path_repo, conteudo, msg):
    url = f"https://api.github.com/repos/{repo}/contents/{path_repo}"
    req = urllib.request.Request(url, headers={"Authorization": f"token {token}", "Accept": "application/vnd.github.v3+json"})
    with urllib.request.urlopen(req) as r: sha = json.loads(r.read())["sha"]
    encoded = base64.b64encode(conteudo.encode("utf-8")).decode()
    payload = json.dumps({"message": msg, "content": encoded, "sha": sha}).encode()
    req2 = urllib.request.Request(url, data=payload, method="PUT", headers={"Authorization": f"token {token}", "Content-Type": "application/json", "Accept": "application/vnd.github.v3+json"})
    with urllib.request.urlopen(req2) as r: return json.loads(r.read())["commit"]["sha"][:7]

sha1 = _push("estudo-de-rede/stripe_billing.py", src_sb, "feat: termo adesao + branding FNI + email pos-pagamento")
print(f"GITHUB OK stripe_billing.py: commit {sha1}")
sha2 = _push("estudo-de-rede/estudo_de_rede.py", src_mn, "feat: wrapper _mostrar_tela_planos_com_termo")
print(f"GITHUB OK estudo_de_rede.py: commit {sha2}")

